{
  "grammar": [
    {
      "pattern": "可以 + [action] + [object] + 嗎？",
      "structure": ["可以", "action", "object", "嗎"],
      "explanation_en": "Use '可以...嗎？' to politely ask for permission or request something. It is a standard polite form in service contexts.",
      "title": "Polite Request with 可以...嗎？",
      "meaning": "May I...? / Can I...?",
      "when_to_use": ["When asking for permission to do something", "When requesting an item or service from a shop or café"],
      "when_not_to_use": ["When making a direct command or demand", "When speaking to close friends in informal settings"],
      "pragmatic_notes": "In Taiwan, using '可以...嗎？' is very common and considered polite. It softens the request and shows respect to the service provider.",
      "word_order_notes": "The structure is: 可以 + verb + object + 嗎. Do not place 嗎 before the verb.",
      "english_contrast": "English uses 'Can I...?' or 'May I...?' at the beginning. Chinese places '可以' at the start and '嗎' at the end.",
      "korean_contrast": "Korean uses '~을/를 주세요' or '~해도 될까요?' which is similar to '可以...嗎？' but the word order is different.",
      "negative_examples": [
        {
          "text": "可以嗎我喝咖啡？",
          "error": "Word order is wrong. '可以' should be followed by the verb, and '嗎' should be at the end."
        }
      ],
      "incorrect_examples": [
        {
          "text": "我喝咖啡可以嗎？",
          "error": "This is grammatically acceptable but less natural. The standard polite request starts with '可以'."
        }
      ],
      "transformation_drills": ["Change '我要一杯咖啡' to a polite request using '可以...嗎？'"],
      "production_drills": ["Ask for a cup of tea politely."],
      "common_error_patterns": ["Placing 嗎 before the verb", "Forgetting 嗎 at the end"],
      "repair_feedback": {
        "word_order": "Remember: 可以 + verb + object + 嗎",
        "politeness": "Using 可以...嗎？ is polite; avoid direct commands.",
        "vocabulary": "Use appropriate verbs like 喝, 吃, 拿, 買."
      }
    },
    {
      "pattern": "想要 + [object]",
      "structure": ["想要", "object"],
      "explanation_en": "Use '想要' to express what you want in a polite and indirect way. It is softer than '要'.",
      "title": "Expressing Wants with 想要",
      "meaning": "I would like...",
      "when_to_use": ["When ordering food or drinks", "When stating a preference politely"],
      "when_not_to_use": ["When making a strong demand", "When you need to be very direct"],
      "pragmatic_notes": "In Taiwan, '想要' is commonly used in service encounters. It sounds more polite than '要' because it implies a desire rather than a demand.",
      "word_order_notes": "Subject + 想要 + object. The subject is often omitted when it's clear.",
      "english_contrast": "English uses 'I would like...' which is similar. Chinese uses '想要' directly before the object.",
      "korean_contrast": "Korean uses '~을/를 원하다' or '~고 싶다' but '想要' is more like '~을/를 갖고 싶다'.",
      "negative_examples": [
        {
          "text": "想要我咖啡。",
          "error": "Word order is wrong. '想要' should be followed by the object, not the subject."
        }
      ],
      "incorrect_examples": [
        {
          "text": "我要一杯咖啡。",
          "error": "This is correct but more direct. '想要' is softer and more polite."
        }
      ],
      "transformation_drills": ["Change '我要紅茶' to a softer request using '想要'"],
      "production_drills": ["Say you would like a cup of green tea."],
      "common_error_patterns": ["Using 想要 with a verb instead of an object", "Forgetting to omit subject when unnecessary"],
      "repair_feedback": {
        "word_order": "Subject + 想要 + object",
        "politeness": "Use 想要 to sound polite; avoid 要 in formal requests.",
        "vocabulary": "Use nouns like 咖啡, 茶, 水."
      }
    },
    {
      "pattern": "不好意思 + [request]",
      "structure": ["不好意思", "request"],
      "explanation_en": "Use '不好意思' as a polite softener before making a request. It means 'Excuse me' or 'Sorry to bother you'.",
      "title": "Polite Softener 不好意思",
      "meaning": "Excuse me, sorry to bother you...",
      "when_to_use": ["When starting a request in a shop or café", "When you need to get someone's attention politely"],
      "when_not_to_use": ["When apologizing for a mistake (use 對不起 instead)", "When speaking to close friends casually"],
      "pragmatic_notes": "In Taiwan, '不好意思' is very common as a polite opener. It shows consideration and is less formal than '對不起'.",
      "word_order_notes": "Place '不好意思' at the beginning of the sentence, followed by the request.",
      "english_contrast": "English uses 'Excuse me' or 'Sorry' at the start. Chinese uses '不好意思' similarly.",
      "korean_contrast": "Korean uses '실례합니다' or '죄송합니다' which are similar but more formal.",
      "negative_examples": [
        {
          "text": "我要咖啡不好意思。",
          "error": "The softener should come before the request, not after."
        }
      ],
      "incorrect_examples": [
        {
          "text": "不好意思，我要一杯咖啡。",
          "error": "This is correct. It is a polite request."
        }
      ],
      "transformation_drills": ["Add '不好意思' to the beginning of '我要一杯水'"],
      "production_drills": ["Politely ask for a menu using '不好意思'."],
      "common_error_patterns": ["Using 不好意思 after the request", "Confusing 不好意思 with 對不起"],
      "repair_feedback": {
        "word_order": "Place 不好意思 at the start.",
        "politeness": "Using 不好意思 makes the request polite.",
        "vocabulary": "Use appropriate request phrases after 不好意思."
      }
    }
  ]
}
